const { ethers } = require("ethers");
require("dotenv").config();

class EthereumService {
  constructor() {
    const rpcUrl = process.env.RPC_URL;
    const privateKey = process.env.PRIVATE_KEY;

    if (!rpcUrl) throw new Error("RPC_URL is required");
    if (!privateKey) throw new Error("PRIVATE_KEY is required");

    this.provider = new ethers.JsonRpcProvider(rpcUrl);
    this.wallet = new ethers.Wallet(privateKey, this.provider);
  }

  async getAddress() {
    return await this.wallet.getAddress();
  }

  async getBalance(address) {
    const target = address || (await this.getAddress());
    return await this.provider.getBalance(target);
  }

  async sendEth(to, amountEth, options = {}) {
    if (!ethers.isAddress(to)) throw new Error("Invalid recipient address");
    const value = ethers.parseEther(String(amountEth));

    const tx = {
      to,
      value,
      gasLimit: options.gasLimit ? BigInt(options.gasLimit) : undefined,
      maxFeePerGas: options.maxFeePerGas ? ethers.parseUnits(String(options.maxFeePerGas), "gwei") : undefined,
      maxPriorityFeePerGas: options.maxPriorityFeePerGas ? ethers.parseUnits(String(options.maxPriorityFeePerGas), "gwei") : undefined
    };

    const response = await this.wallet.sendTransaction(tx);
    return await response.wait();
  }

  getContract(address, abi) {
    if (!ethers.isAddress(address)) throw new Error("Invalid contract address");
    if (!Array.isArray(abi)) throw new Error("ABI must be an array");
    return new ethers.Contract(address, abi, this.wallet);
  }

  async callContractMethod(contractAddress, abi, methodName, args = [], options = {}) {
    const contract = this.getContract(contractAddress, abi);
    if (typeof contract[methodName] !== "function") {
      throw new Error(`Method not found: ${methodName}`);
    }

    const overrides = {};
    if (options.value !== undefined) overrides.value = ethers.parseEther(String(options.value));
    if (options.gasLimit !== undefined) overrides.gasLimit = BigInt(options.gasLimit);
    if (options.maxFeePerGas !== undefined) overrides.maxFeePerGas = ethers.parseUnits(String(options.maxFeePerGas), "gwei");
    if (options.maxPriorityFeePerGas !== undefined) overrides.maxPriorityFeePerGas = ethers.parseUnits(String(options.maxPriorityFeePerGas), "gwei");

    const finalArgs = Array.isArray(args) ? [...args] : [];
    if (Object.keys(overrides).length > 0) finalArgs.push(overrides);

    const tx = await contract[methodName](...finalArgs);
    if (tx && typeof tx.wait === "function") {
      return await tx.wait();
    }
    return tx;
  }

  async readContractMethod(contractAddress, abi, methodName, args = []) {
    const contract = this.getContract(contractAddress, abi);
    if (typeof contract[methodName] !== "function") {
      throw new Error(`Method not found: ${methodName}`);
    }
    return await contract[methodName](...args);
  }

  async estimateGasForEthTransfer(to, amountEth) {
    if (!ethers.isAddress(to)) throw new Error("Invalid recipient address");
    return await this.provider.estimateGas({
      to,
      value: ethers.parseEther(String(amountEth))
    });
  }

  async getNonce(address) {
    const target = address || (await this.getAddress());
    return await this.provider.getTransactionCount(target, "latest");
  }
}

module.exports = EthereumService;

